  var pickMin = (typeof FRAME_DEF_STEP2A_V2_DUAL_CAND_OVERLAP_PICK_MIN_MM2 === 'number' && isFinite(FRAME_DEF_STEP2A_V2_DUAL_CAND_OVERLAP_PICK_MIN_MM2))
