    var gx0 = Math.floor((Number(b.minx) || 0) / cellMm), gy0 = Math.floor((Number(b.miny) || 0) / cellMm);
    var gx1 = Math.floor((Number(b.maxx) || 0) / cellMm), gy1 = Math.floor((Number(b.maxy) || 0) / cellMm);
