      var nFacingScore = (Number(vv.minusFacingArea) || 0) + (Number(vv.minusFacingMax) || 0) * 0.20;
      var scoreGap = Math.abs(pScore - nScore);
      // 유사면적(near tie) 판정 범위를 넓혀 마주보는 방향 타이브레이커 적용 빈도를 높인다.
