function frameDefRefreshPanelState() {
  frameDefEnsureDebugPanel();
  frameDefRefreshDefinedGroupList(); frameDefRenderClassList();
  var overlayChk = document.getElementById('frameDefPreviewOverlayChk');
  var dimOthersChk = document.getElementById('frameDefDimOthersChk');
  var gapChk = document.getElementById('frameDefShowGapIssuesChk');
  var orientSplitChk = document.getElementById('frameDefUseOrientationChk');
  var boundaryBtn = document.getElementById('frameDefWallBoundaryEditBtn');
  var rotateBtn = document.getElementById('frameDefWallRotateBtn');
  var revertBtn = document.getElementById('frameDefWallRevertBtn');
  var saveBtn = document.getElementById('frameDefWallSaveBtn');
  var editSum = document.getElementById('frameDefEditSummary');
  var st = frameDefGetState();
  function syncModeBtn(btn, mode) {
    if (!btn) return;
    var on = String(st.editMode || '') === String(mode || '');
    btn.style.background = on ? '#2563eb' : '#fff';
    btn.style.border = on ? '1px solid #2563eb' : '1px solid #d0d7de';
    btn.style.color = on ? '#fff' : '#24292f';
  }
  if (overlayChk) overlayChk.checked = frameDefGetState().previewVisible !== false;
  if (dimOthersChk) dimOthersChk.checked = frameDefGetState().dimOthers !== false;
  if (gapChk) gapChk.checked = frameDefGetState().showGapIssues === true;
  if (orientSplitChk) orientSplitChk.checked = frameDefGetState().useOrientationSplit === true;
  syncModeBtn(boundaryBtn, 'wall-boundary');
  syncModeBtn(rotateBtn, 'wall-rotate');
  if (revertBtn) revertBtn.disabled = !st.selectedWallKey;
  if (saveBtn) saveBtn.disabled = !Object.keys(st.pendingWallOverrides || {}).length;
  if (editSum) {
    var modeLabel = st.editMode === 'wall-boundary' ? '\uBCBD \uACBD\uACC4 \uD3B8\uC9D1'
      : (st.editMode === 'wall-rotate' ? '\uBCBD\uCCB4 \uD68C\uC804' : '\uC5C6\uC74C');
    var wallTxt = st.selectedWallKey ? (' / \uC120\uD0DD wall ' + String(st.selectedWallKey).split('|').slice(-2).join(' | ')) : '';
    var issueTxt = st.selectedIssueId ? (' / issue ' + String(st.selectedIssueId)) : '';
    var limitTxt = st.gapIssueLimited ? ' / \uBE48\uAD6C\uAC04 \uD45C\uC2DC \uC81C\uD55C' : '';
    editSum.textContent = '\uBAA8\uB4DC: ' + modeLabel + ' / \uBBF8\uC800\uC7A5 \uC218\uC815 ' + String(Object.keys(st.pendingWallOverrides || {}).length) + '\uAC1C' + wallTxt + issueTxt + limitTxt;
  }
  frameDefRenderDebugPanel();
}
function frameDefResetState(opts) {
  var st = frameDefGetState(), keepLabel = !!(opts && opts.keepLabel), keepCommit = !!(opts && opts.keepCommit);
  st.columns = []; st.walls = []; st.columnClasses = []; st.wallClasses = [];
  st.activeClassKey = ''; st.activeSelectionScope = ''; st.selectedDefinedGroupId = '';
  st.gapIssues = []; st.selectedWallKey = ''; st.selectedIssueId = ''; st.editDragState = null; st.editSnapGuide = null;
  st.editMode = '';
  st.loadedWallOverrides = {}; st.pendingWallOverrides = {}; st.loadedWallOverrideEntityIds = []; st.autoRotatedWallKeys = {};
  st.rawSegs = []; st.descs = []; st.debugColumns = []; st.overlayCoverageIndex = null; st.gapIssueLimited = false;
  st.wallStep2aHatchWalls = [];
  st.wallStep2aSourceSegs = [];
  st.wallStep2aSourcePairs = [];
  st.wallStep2aClosedLoopChains = [];
  st.wallStep2aClosedLoopDebug = [];
  st.wallStep2aSplitChainCounts = { closed: 0, open: 0, openWalls: 0 };
  st.wallStep2bByBackend = { cnn: [], xgb: [], rf: [], mlp: [], gnn: [] };
  st.debugStep2bLastMessage = '';
  if (!keepCommit) st.lastCommitId = null;
  if (typeof window !== 'undefined') {
    window.__frameDefGraphDebugContext = null;
    window.frameDefLastDebug = null;
  }
  if (!keepLabel) { var labelEl = document.getElementById('frameDefLabelInput'); if (labelEl) labelEl.value = '\uACE8\uC870'; }
  frameDefRefreshPanelState(); draw();
}
function frameDefHandleContextChange(commitId) {
  var st = frameDefGetState(), cid = String(commitId == null ? '' : commitId).trim();
  if (!cid) { frameDefResetState({ keepLabel: true }); return; }
  frameDefRefreshDefinedGroupList();
  if (st.lastCommitId && String(st.lastCommitId) !== cid) frameDefResetState({ keepLabel: true });
}

function frameDefBindClassListEvents(el) {
  if (!el || el.dataset.frameDefBound === '1') return;
  el.dataset.frameDefBound = '1';
  el.addEventListener('click', function(e) {
    var row = e.target && e.target.closest ? e.target.closest('[data-frame-class]') : null;
    if (!row) return;
    var key = String(row.getAttribute('data-frame-class') || '').trim();
    if (key) frameDefSelectClass(key, false);
  });
}
function bindFrameDefPanelEvents() {
  var panel = document.getElementById('featurePanel-frame-object-define');
  if (!panel || panel.dataset.frameDefPanelBound === '1') return;
  panel.dataset.frameDefPanelBound = '1';
  var applyBtn = document.getElementById('frameDefApplyBtn');
  var selAllBtn = document.getElementById('frameDefSelectAllBtn');
  var selColsBtn = document.getElementById('frameDefSelectColumnsBtn');
  var selWallsBtn = document.getElementById('frameDefSelectWallsBtn');
  var definedSel = document.getElementById('frameDefDefinedList');
  var definedBtn = document.getElementById('frameDefDefinedSelectBtn');
  var overlayChk = document.getElementById('frameDefPreviewOverlayChk');
  var dimOthersChk = document.getElementById('frameDefDimOthersChk');
  var gapChk = document.getElementById('frameDefShowGapIssuesChk');
  var orientSplitChk = document.getElementById('frameDefUseOrientationChk');
  var step114ToggleSelectBtn = document.getElementById('frameDefDebugStep114ToggleSelectBtn');
  var step114ToggleHatchChk = document.getElementById('frameDefDebugStep114ToggleHatchChk');
  var boundaryBtn = document.getElementById('frameDefWallBoundaryEditBtn');
  var rotateBtn = document.getElementById('frameDefWallRotateBtn');
  var revertBtn = document.getElementById('frameDefWallRevertBtn');
  var saveBtn = document.getElementById('frameDefWallSaveBtn');
  frameDefBindClassListEvents(document.getElementById('frameDefColumnClassList'));
  frameDefBindClassListEvents(document.getElementById('frameDefWallClassList'));
  /* frameDefAutoDetectBtn 클릭은 workspace.html 이벤트 위임에서 처리 */
  if (selAllBtn) selAllBtn.addEventListener('click', function() { frameDefSelectScope('all', false); });
  if (selColsBtn) selColsBtn.addEventListener('click', function() { frameDefSelectScope('column', false); });
  if (selWallsBtn) selWallsBtn.addEventListener('click', function() { frameDefSelectScope('wall', false); });
  if (applyBtn) applyBtn.addEventListener('click', function() { frameDefApplySelection(); });
  if (definedSel) definedSel.addEventListener('change', function() { var gid = String(definedSel.value || '').trim(); if (gid) frameDefSelectDefinedGroup(gid, true); });
  if (definedBtn) definedBtn.addEventListener('click', function() {
    var gid = String((definedSel && definedSel.value) || '').trim();
    if (!gid) { showMsg('msg', '\uC120\uD0DD\uB41C \uC801\uC6A9 \uBB36\uC74C\uC774 \uC5C6\uC2B5\uB2C8\uB2E4.', 'info'); return; }
    frameDefSelectDefinedGroup(gid, false);
  });
  if (step114ToggleSelectBtn) step114ToggleSelectBtn.addEventListener('click', function() {
    if (typeof frameDefGetState !== 'function' || typeof frameDefSegEntityIds !== 'function' || typeof frameDefUniqueEntityIds !== 'function' || typeof frameDefSetSelectedEntities !== 'function') return;
    var s = frameDefGetState();
    var chains114 = Array.isArray((s.wallStep11ByCategory || {})['114']) ? (s.wallStep11ByCategory || {})['114'] : [];
    var ids114 = [];
    for (var i = 0; i < chains114.length; i++) {
      var segIds114 = frameDefSegEntityIds(chains114[i]);
      if (segIds114 && segIds114.length) for (var j = 0; j < segIds114.length; j++) ids114.push(segIds114[j]);
    }
    ids114 = frameDefUniqueEntityIds(ids114);
    frameDefSetSelectedEntities(ids114);
    if (typeof frameDefRenderClassList === 'function') frameDefRenderClassList();
    if (typeof draw === 'function') draw();
  });
  if (step114ToggleHatchChk) {
    step114ToggleHatchChk.checked = frameDefGetState().debugStep114ShowHatch === true;
    step114ToggleHatchChk.addEventListener('change', function() {
      frameDefGetState().debugStep114ShowHatch = !!step114ToggleHatchChk.checked;
      draw();
    });
  }
  if (overlayChk) {
    overlayChk.checked = frameDefGetState().previewVisible !== false;
    overlayChk.addEventListener('change', function() { frameDefGetState().previewVisible = !!overlayChk.checked; draw(); });
  }
  if (dimOthersChk) {
    dimOthersChk.checked = frameDefGetState().dimOthers !== false;
    dimOthersChk.addEventListener('change', function() { frameDefGetState().dimOthers = !!dimOthersChk.checked; draw(); });
  }
  if (gapChk) {
    gapChk.checked = frameDefGetState().showGapIssues === true;
    gapChk.addEventListener('change', function() { frameDefGetState().showGapIssues = !!gapChk.checked; draw(); });
  }
  if (orientSplitChk) {
    orientSplitChk.checked = frameDefGetState().useOrientationSplit === true;
    orientSplitChk.addEventListener('change', function() {
      var st = frameDefGetState();
      st.useOrientationSplit = !!orientSplitChk.checked;
      frameDefRebuildColumnClassesFromState();
      if (st.selectedDefinedGroupId) {
        var g = (st.definedGroups || []).find(function(x) { return String(x.group_id) === String(st.selectedDefinedGroupId); });
        frameDefSetSelectedEntities(g ? (g.entity_ids || []) : []);
      } else if (st.activeClassKey) {
        var cls = frameDefClassByKey(st.activeClassKey);
        frameDefSetSelectedEntities(cls ? (cls.entity_ids || []) : []);
      } else if (st.activeSelectionScope) {
        frameDefSetSelectedEntities(frameDefCollectScopeEntityIds(st.activeSelectionScope));
      } else {
        frameDefSetSelectedEntities([]);
      }
      frameDefRenderClassList();
      draw();
    });
  }
  if (boundaryBtn) boundaryBtn.addEventListener('click', function() { frameDefToggleEditMode('wall-boundary'); });
  if (rotateBtn) rotateBtn.addEventListener('click', function() { frameDefToggleEditMode('wall-rotate'); });
  if (revertBtn) revertBtn.addEventListener('click', function() { frameDefRevertSelectedWallOverride(); });
  if (saveBtn) saveBtn.addEventListener('click', function() { frameDefSaveWallOverrides(); });
  frameDefRefreshPanelState();
}

